import pytest

def snake_to_camel(s: str) -> str:
    parts = s.split('_')
    return parts[0] + ''.join(p.capitalize() for p in parts[1:])

class TestSnakeToCamel:
    def test_happy_path(self):
        assert snake_to_camel("snake_case") == "snakeCase"
        assert snake_to_camel("another_snake_case_example") == "anotherSnakeCaseExample"
        assert snake_to_camel("single_word") == "singleWord"

    def test_empty_string(self):
        assert snake_to_camel("") == ""

    def test_no_underscores(self):
        assert snake_to_camel("camelcase") == "camelcase"
        assert snake_to_camel("CAPITAL") == "CAPITAL"

    def test_leading_underscore(self):
        assert snake_to_camel("_leading") == "Leading"
        assert snake_to_camel("__leading") == "Leading"
        assert snake_to_camel("___leading") == "Leading"

    def test_trailing_underscore(self):
        assert snake_to_camel("trailing_") == "trailing"
        assert snake_to_camel("trailing__") == "trailing"
        assert snake_to_camel("trailing___") == "trailing"

    def test_multiple_underscores(self):
        assert snake_to_camel("multiple__underscores") == "multipleUnderscores"
        assert snake_to_camel("multiple___underscores") == "multipleUnderscores"

    def test_numbers(self):
        assert snake_to_camel("snake_case_123") == "snakeCase123"
        assert snake_to_camel("123_snake_case") == "123SnakeCase"
        assert snake_to_camel("snake_123_case") == "snake123Case"

    def test_mixed_case(self):
        assert snake_to_camel("snake_Case") == "snakeCase"
        assert snake_to_camel("Snake_case") == "SnakeCase"
        assert snake_to_camel("sNaKe_cAsE") == "sNaKeCaSe"

    def test_empty_parts(self):
        assert snake_to_camel("___") == ""
        assert snake_to_camel("____") == ""

    def test_single_character_parts(self):
        assert snake_to_camel("a_b_c") == "aBC"
        assert snake_to_camel("a_B_c") == "aBC"

    def test_unicode(self):
        assert snake_to_camel("unicode_test_äöü") == "unicodeTestÄöü"
        assert snake_to_camel("test_unicode_你好世界") == "testUnicode你好世界"
